#include <stdio.h>
#include <string.h>

int minTears(char *s) {
    int n = strlen(s);
    if (n % 2 != 0) return -1;
    if (n == 1) return 0;
    int i;
    for (i = 0; i < n / 2; i++) {
        if (s[i] != s[0]) break;
    }
    if (i == n / 2) return minTears(s + n / 2);
    for (i = n / 2; i < n; i++) {
        if (s[i] != s[n / 2]) break;
    }
    if (i == n) return minTears(s);
    return 1 + minTears(s) + minTears(s + n / 2);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[100001];
        scanf("%s", s);
        printf("%d\n", minTears(s));
    }
    return 0;
}

