import java.util.Scanner;
public class Main {
    public static int minTears(String s) {
        int n = s.length();
        if (n % 2 != 0) return -1;
        if (n == 1) return 0;
        int i;
        for (i = 0; i < n / 2; i++) {
            if (s.charAt(i) != s.charAt(0)) break;
        }
        if (i == n / 2) return minTears(s.substring(n / 2));
        for (i = n / 2; i < n; i++) {
            if (s.charAt(i) != s.charAt(n / 2)) break;
        }
        if (i == n) return minTears(s);
        return 1 + minTears(s) + minTears(s.substring(n / 2));
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String s = sc.next();
            System.out.println(minTears(s));
        }
    }
