def minTears(s):
    n = len(s)
    if n % 2 != 0: return -1
    if n == 1: return 0
    i = 0
    while i < n // 2 and s[i] == s[0]: i += 1
    if i == n // 2: return minTears(s[n // 2:])
    i = n // 2
    while i < n and s[i] == s[n // 2]: i += 1
    if i == n: return minTears(s)
    return 1 + minTears(s) + minTears(s[n // 2:])

